import React, { useState } from 'react';
import styled from 'styled-components';
import Container from '../components/common/Container';
import TestimonialInput from '../components/testimonials/TestimonialInput';
import EnhancementPreview from '../components/testimonials/EnhancementPreview';
import ApprovalLink from '../components/testimonials/ApprovalLink';

const EnhancePage = () => {
  const [originalText, setOriginalText] = useState('');
  const [enhancedText, setEnhancedText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isComplete, setIsComplete] = useState(false);
  const [approvalLink, setApprovalLink] = useState('');

  const handleSubmit = async (text) => {
    setOriginalText(text);
    setIsProcessing(true);

    // Simulate API call to AI enhancement service
    setTimeout(() => {
      const enhanced = "Working with this coach transformed how I approach challenges. Their methods didn't just provide temporary solutions—they fundamentally changed my perspective. I went from feeling overwhelmed to confident and accomplished, with measurable results in just weeks.";
      setEnhancedText(enhanced);
      setIsProcessing(false);
      setIsComplete(true);
      setApprovalLink(`https://testy.app/verify/${Math.random().toString(36).substring(2, 15)}`);
    }, 2000);
  };

  return (
    <Container>
      <PageHeader>
        <h1>Enhance Your Testimonial</h1>
        <p>Enter your client's original testimonial to transform it into a compelling story</p>
      </PageHeader>

      {!isComplete ? (
        <TestimonialInput onSubmit={handleSubmit} isProcessing={isProcessing} />
      ) : (
        <>
          <EnhancementPreview original={originalText} enhanced={enhancedText} />
          <ApprovalLink link={approvalLink} />
        </>
      )}
    </Container>
  );
};

const PageHeader = styled.div`
  text-align: center;
  margin-bottom: 40px;
`;

export default EnhancePage;
